SELECT [Unique Identifier Pst_ Docnts].Code, [Posted Whse_ Shipment Header].No_, [Posted Whse_ Shipment Header].[Whse_ Shipment No_], [Registered Whse_ Activity Line].No_, [Registered Whse_ Activity Line].[Whse_ Activity No_], [Registered Whse_ Activity Line].[Source No_], [Posted Whse_ Shipment Header].[Warehouse Speciality Code], [Posted Whse_ Shipment Header].[Warehouse Note]
FROM ([Unique Identifier Pst_ Docnts] INNER JOIN [Registered Whse_ Activity Line] ON ([Unique Identifier Pst_ Docnts].[Line No_] = [Registered Whse_ Activity Line].[Line No_]) AND ([Unique Identifier Pst_ Docnts].No_ = [Registered Whse_ Activity Line].No_)) INNER JOIN [Posted Whse_ Shipment Header] ON [Registered Whse_ Activity Line].[Whse_ Document No_] = [Posted Whse_ Shipment Header].[Whse_ Shipment No_]
GROUP BY [Unique Identifier Pst_ Docnts].Code, [Posted Whse_ Shipment Header].No_, [Posted Whse_ Shipment Header].[Whse_ Shipment No_], [Registered Whse_ Activity Line].No_, [Registered Whse_ Activity Line].[Whse_ Activity No_], [Registered Whse_ Activity Line].[Source No_], [Posted Whse_ Shipment Header].[Warehouse Speciality Code], [Posted Whse_ Shipment Header].[Warehouse Note]
HAVING ((([Unique Identifier Pst_ Docnts].Code)=[forms]![principale]![filtrocodiceBox]));

